1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { IsNull, Repository } from 'typeorm';
4	import { AppException } from '../../common/exceptions/app.exception';
5	import { AuditService } from '../audit/audit.service';
6	import { ReservationService } from '../reservation/reservation.service';
7	import { ScopePolicyService } from '../access-control/scope-policy.service';
8	import { NotificationService } from './notification.service';
9	import { SupportTicketEntity } from './entities/support-ticket.entity';
10	import { CreateSupportTicketDto } from './dto/create-support-ticket.dto';
11	import { SupportTicketListQueryDto } from './dto/support-ticket-list-query.dto';
12	
13	const SUPPORT_TICKET_STATUS_OPEN = 'OPEN';
14	const SUPPORT_TICKET_STATUS_ESCALATED = 'ESCALATED';
15	const SUPPORT_TICKET_STATUS_RESOLVED = 'RESOLVED';
16	const SUPPORT_TICKET_STATUS_CLOSED = 'CLOSED';
17	
18	@Injectable()
19	export class SupportTicketService {
20	  constructor(
21	    private readonly reservationService: ReservationService,
22	    private readonly scopePolicyService: ScopePolicyService,
23	    private readonly auditService: AuditService,
24	    private readonly notificationService: NotificationService,
25	    @InjectRepository(SupportTicketEntity)
26	    private readonly supportTicketRepository: Repository<SupportTicketEntity>
27	  ) {}
28	
29	  async createSupportTicket(userId: string, payload: CreateSupportTicketDto): Promise<Record<string, unknown>> {
30	    await this.reservationService.ensureReservationForAttachment(userId, payload.reservation_id);
31	
32	    const ticket = await this.supportTicketRepository.save(
33	      this.supportTicketRepository.create({
34	        reservationId: payload.reservation_id,
35	        ownerUserId: userId,
36	        category: payload.category,
37	        description: payload.description,
38	        messageId: payload.message_id ?? null,
39	        status: SUPPORT_TICKET_STATUS_OPEN
40	      })
41	    );
42	
43	    await this.auditService.appendLog({
44	      entityType: 'support_ticket',
45	      entityId: ticket.id,
46	      action: 'support.ticket.create',
47	      actorId: userId,
48	      payload: {
49	        reservation_id: payload.reservation_id,
50	        category: payload.category
51	      }
52	    });
53	
54	    return this.mapSupportTicket(ticket);
55	  }
56	
57	  async escalateSupportTicket(
58	    userId: string,
59	    ticketId: string,
60	    payload: { reason?: string }
61	  ): Promise<Record<string, unknown>> {
62	    const ticket = await this.getSupportTicketOrThrow(ticketId);
63	
64	    const roles = await this.scopePolicyService.getRoles(userId);
65	    const isStaffOrOps = roles.includes('staff') || roles.includes('ops_admin');
66	    const isOwner = ticket.ownerUserId === userId;
67	
68	    if (!isStaffOrOps && !isOwner) {
69	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
70	    }
71	
72	    if (isOwner) {
73	      await this.reservationService.ensureReservationForAttachment(userId, ticket.reservationId);
74	    } else {
75	      await this.reservationService.ensureReservationRecordExists(ticket.reservationId);
76	    }
77	    if (ticket.status !== SUPPORT_TICKET_STATUS_OPEN) {
78	      throw new AppException('SUPPORT_TICKET_INVALID_STATE', 'Ticket cannot be escalated from current state', {}, 422);
79	    }
80	
81	    ticket.status = SUPPORT_TICKET_STATUS_ESCALATED;
82	    ticket.version += 1;
83	    const saved = await this.supportTicketRepository.save(ticket);
84	
85	    await this.auditService.appendLog({
86	      entityType: 'support_ticket',
87	      entityId: saved.id,
88	      action: 'support.ticket.escalate',
89	      actorId: userId,
90	      payload: {
91	        reservation_id: saved.reservationId,
92	        owner_user_id: saved.ownerUserId,
93	        reason: payload.reason ?? null
94	      }
95	    });
96	
97	    await this.notificationService.notifyTicketOwner(saved.ownerUserId, userId, 'support_ticket_escalated', 'Support ticket escalated', {
98	      ticket_id: saved.id,
99	      reservation_id: saved.reservationId,
100	      reason: payload.reason ?? null
101	    });
102	
103	    return this.mapSupportTicket(saved);
104	  }
105	
106	  async resolveSupportTicket(
107	    userId: string,
108	    ticketId: string,
109	    payload: { resolution_note?: string }
110	  ): Promise<Record<string, unknown>> {
111	    const ticket = await this.getSupportTicketOrThrow(ticketId);
112	
113	    const roles = await this.scopePolicyService.getRoles(userId);
114	    const isStaffOrOps = roles.includes('staff') || roles.includes('ops_admin');
115	    if (!isStaffOrOps) {
116	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
117	    }
118	
119	    await this.reservationService.ensureReservationRecordExists(ticket.reservationId);
120	
121	    const validSourceStatuses = new Set([SUPPORT_TICKET_STATUS_OPEN, SUPPORT_TICKET_STATUS_ESCALATED]);
122	    if (!validSourceStatuses.has(ticket.status)) {
123	      throw new AppException('SUPPORT_TICKET_INVALID_STATE', 'Ticket cannot be resolved from current state', {}, 422);
124	    }
125	
126	    const previousStatus = ticket.status;
127	    ticket.status = SUPPORT_TICKET_STATUS_RESOLVED;
128	    ticket.version += 1;
129	    const saved = await this.supportTicketRepository.save(ticket);
130	
131	    await this.auditService.appendLog({
132	      entityType: 'support_ticket',
133	      entityId: saved.id,
134	      action: 'support.ticket.resolve',
135	      actorId: userId,
136	      payload: {
137	        reservation_id: saved.reservationId,
138	        previous_status: previousStatus,
139	        resolution_note: payload.resolution_note ?? null
140	      }
141	    });
142	
143	    await this.notificationService.notifyTicketOwner(saved.ownerUserId, userId, 'support_ticket_resolved', 'Support ticket resolved', {
144	      ticket_id: saved.id,
145	      reservation_id: saved.reservationId,
146	      resolution_note: payload.resolution_note ?? null,
147	      previous_status: previousStatus
148	    });
149	
150	    return this.mapSupportTicket(saved);
151	  }
152	
153	  async closeSupportTicket(userId: string, ticketId: string, payload: { close_note?: string }): Promise<Record<string, unknown>> {
154	    const ticket = await this.getSupportTicketOrThrow(ticketId);
155	
156	    const roles = await this.scopePolicyService.getRoles(userId);
157	    const isStaffOrOps = roles.includes('staff') || roles.includes('ops_admin');
158	    if (!isStaffOrOps) {
159	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
160	    }
161	
162	    await this.reservationService.ensureReservationRecordExists(ticket.reservationId);
163	
164	    if (ticket.status !== SUPPORT_TICKET_STATUS_RESOLVED) {
165	      throw new AppException('SUPPORT_TICKET_INVALID_STATE', 'Ticket can only be closed after resolution', {}, 422);
166	    }
167	
168	    ticket.status = SUPPORT_TICKET_STATUS_CLOSED;
169	    ticket.version += 1;
170	    const saved = await this.supportTicketRepository.save(ticket);
171	
172	    await this.auditService.appendLog({
173	      entityType: 'support_ticket',
174	      entityId: saved.id,
175	      action: 'support.ticket.close',
176	      actorId: userId,
177	      payload: {
178	        reservation_id: saved.reservationId,
179	        close_note: payload.close_note ?? null
180	      }
181	    });
182	
183	    await this.notificationService.notifyTicketOwner(saved.ownerUserId, userId, 'support_ticket_closed', 'Support ticket closed', {
184	      ticket_id: saved.id,
185	      reservation_id: saved.reservationId,
186	      close_note: payload.close_note ?? null
187	    });
188	
189	    return this.mapSupportTicket(saved);
190	  }
191	
192	  async listSupportTickets(userId: string, query: SupportTicketListQueryDto): Promise<Record<string, unknown>> {
193	    const roles = await this.scopePolicyService.getRoles(userId);
194	    const isOpsOrStaff = roles.includes('ops_admin') || roles.includes('staff');
195	
196	    const qb = this.supportTicketRepository.createQueryBuilder('t').where('t.deleted_at IS NULL');
197	    if (query.status) {
198	      qb.andWhere('t.status = :status', { status: query.status });
199	    }
200	    if (query.reservation_id) {
201	      qb.andWhere('t.reservation_id = :reservationId', { reservationId: query.reservation_id });
202	    }
203	    if (roles.includes('staff') && !roles.includes('ops_admin')) {
204	      const scopeIds = await this.scopePolicyService.getUserScopeIds(userId);
205	      if (scopeIds.length === 0) {
206	        qb.andWhere('1 = 0');
207	      } else {
208	        qb.andWhere(
209	          `EXISTS (
210	            SELECT 1
211	            FROM reservations r
212	            INNER JOIN reservation_data_scopes rds ON rds.reservation_id = r.id AND rds.deleted_at IS NULL
213	            WHERE r.id = t.reservation_id
214	              AND r.deleted_at IS NULL
215	              AND rds.scope_id IN (:...scopeIds)
216	          )`,
217	          { scopeIds }
218	        );
219	      }
220	    } else if (!isOpsOrStaff) {
221	      qb.andWhere('t.owner_user_id = :ownerId', { ownerId: userId });
222	    }
223	
224	    qb.orderBy('t.created_at', 'DESC').addOrderBy('t.id', 'DESC');
225	    qb.skip((query.page - 1) * query.page_size).take(query.page_size);
226	
227	    const [items, total] = await qb.getManyAndCount();
228	    return {
229	      items: items.map((item) => ({
230	        ...this.mapSupportTicket(item)
231	      })),
232	      page: query.page,
233	      page_size: query.page_size,
234	      total
235	    };
236	  }
237	
238	  private async getSupportTicketOrThrow(ticketId: string): Promise<SupportTicketEntity> {
239	    const ticket = await this.supportTicketRepository.findOne({ where: { id: ticketId, deletedAt: IsNull() } });
240	    if (!ticket) {
241	      throw new AppException('NOT_FOUND', 'Support ticket not found', { ticket_id: ticketId }, 404);
242	    }
243	
244	    return ticket;
245	  }
246	
247	  private mapSupportTicket(ticket: SupportTicketEntity): Record<string, unknown> {
248	    return {
249	      ticket_id: ticket.id,
250	      reservation_id: ticket.reservationId,
251	      status: ticket.status,
252	      category: ticket.category,
253	      description: ticket.description,
254	      message_id: ticket.messageId,
255	      created_at: ticket.createdAt.toISOString(),
256	      updated_at: ticket.updatedAt.toISOString(),
257	      version: ticket.version
258	    };
259	  }
260	}
