1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { IsNull, Repository, SelectQueryBuilder } from 'typeorm';
4	import { AppException } from '../../common/exceptions/app.exception';
5	import { ReservationEntity } from '../reservation/entities/reservation.entity';
6	import { AccessControlService } from './access-control.service';
7	import { DataScopeEntity } from './entities/data-scope.entity';
8	import { ReservationDataScopeEntity } from './entities/reservation-data-scope.entity';
9	import { UserDataScopeEntity } from './entities/user-data-scope.entity';
10	
11	const DEFAULT_CLINIC_SCOPE_KEY = 'default_clinic';
12	
13	@Injectable()
14	export class ScopePolicyService {
15	  constructor(
16	    private readonly accessControlService: AccessControlService,
17	    @InjectRepository(DataScopeEntity)
18	    private readonly dataScopeRepository: Repository<DataScopeEntity>,
19	    @InjectRepository(UserDataScopeEntity)
20	    private readonly userDataScopeRepository: Repository<UserDataScopeEntity>,
21	    @InjectRepository(ReservationDataScopeEntity)
22	    private readonly reservationDataScopeRepository: Repository<ReservationDataScopeEntity>
23	  ) {}
24	
25	  async getRoles(userId: string): Promise<string[]> {
26	    return (await this.accessControlService.getUserRoleNames(userId)).map((role) => role.toLowerCase());
27	  }
28	
29	  async getUserScopeIds(userId: string): Promise<string[]> {
30	    const rows = await this.userDataScopeRepository.find({
31	      where: { userId, deletedAt: IsNull() },
32	      select: { scopeId: true }
33	    });
34	    return [...new Set(rows.map((row) => row.scopeId))];
35	  }
36	
37	  async assignReservationDefaultScopeFromActor(actorUserId: string, reservationId: string, roles?: string[]): Promise<void> {
38	    const roleSet = roles ?? (await this.getRoles(actorUserId));
39	    if (!roleSet.includes('staff') && !roleSet.includes('merchant')) {
40	      return;
41	    }
42	
43	    const scopeIds = await this.getUserScopeIds(actorUserId);
44	    if (scopeIds.length === 0) {
45	      throw new AppException(
46	        'RESERVATION_SCOPE_REQUIRED',
47	        'Staff or merchant must be mapped to at least one data scope',
48	        {},
49	        422
50	      );
51	    }
52	
53	    const existing = await this.reservationDataScopeRepository.findOne({
54	      where: {
55	        reservationId,
56	        scopeId: scopeIds[0],
57	        deletedAt: IsNull()
58	      }
59	    });
60	    if (!existing) {
61	      await this.reservationDataScopeRepository.save(
62	        this.reservationDataScopeRepository.create({
63	          reservationId,
64	          scopeId: scopeIds[0]
65	        })
66	      );
67	    }
68	  }
69	
70	  /**
71	   * Tags new reservations with the default clinic data scope so staff/merchant (and migration-era behavior) stay aligned.
72	   * Patient-created rows previously had no reservation_data_scopes until this hook.
73	   */
74	  async ensureDefaultClinicReservationScope(reservationId: string): Promise<void> {
75	    const scope = await this.dataScopeRepository.findOne({
76	      where: { scopeKey: DEFAULT_CLINIC_SCOPE_KEY, deletedAt: IsNull() }
77	    });
78	    if (!scope) {
79	      return;
80	    }
81	
82	    const existing = await this.reservationDataScopeRepository.findOne({
83	      where: { reservationId, scopeId: scope.id, deletedAt: IsNull() }
84	    });
85	    if (existing) {
86	      return;
87	    }
88	
89	    await this.reservationDataScopeRepository.save(
90	      this.reservationDataScopeRepository.create({
91	        reservationId,
92	        scopeId: scope.id
93	      })
94	    );
95	  }
96	
97	  async assertReservationInScope(userId: string, reservation: ReservationEntity, roles?: string[]): Promise<void> {
98	    const roleSet = roles ?? (await this.getRoles(userId));
99	    if (await this.canAccessReservation(userId, reservation, roleSet)) {
100	      return;
101	    }
102	
103	    throw new AppException('FORBIDDEN', 'Reservation is out of scope', { reservation_id: reservation.id }, 403);
104	  }
105	
106	  async canAccessReservation(userId: string, reservation: ReservationEntity, roles?: string[]): Promise<boolean> {
107	    const roleSet = roles ?? (await this.getRoles(userId));
108	
109	    if (roleSet.includes('ops_admin')) {
110	      return true;
111	    }
112	
113	    const isPatientOwner = roleSet.includes('patient') && reservation.patientId === userId;
114	    const isAssignedProvider = roleSet.includes('provider') && reservation.providerId === userId;
115	    if (isPatientOwner || isAssignedProvider) {
116	      return true;
117	    }
118	
119	    if (roleSet.includes('staff') || roleSet.includes('merchant')) {
120	      return this.hasScopedClinicAccess(userId, reservation.id);
121	    }
122	
123	    return false;
124	  }
125	
126	  async applyReservationScopeQuery(
127	    qb: SelectQueryBuilder<ReservationEntity>,
128	    userId: string,
129	    roles?: string[]
130	  ): Promise<void> {
131	    const roleSet = roles ?? (await this.getRoles(userId));
132	
133	    if (roleSet.includes('ops_admin')) {
134	      return;
135	    }
136	
137	    const hasPatient = roleSet.includes('patient');
138	    const hasProvider = roleSet.includes('provider');
139	    const hasStaff = roleSet.includes('staff');
140	    const hasMerchant = roleSet.includes('merchant');
141	
142	    const conditions: string[] = [];
143	    if (hasPatient) {
144	      conditions.push('r.patient_id = :scopeUserId');
145	    }
146	    if (hasProvider) {
147	      conditions.push('r.provider_id = :scopeUserId');
148	    }
149	    if (hasStaff || hasMerchant) {
150	      const scopeIds = await this.getUserScopeIds(userId);
151	      if (scopeIds.length > 0) {
152	        conditions.push(
153	          'EXISTS (SELECT 1 FROM reservation_data_scopes rds WHERE rds.reservation_id = r.id AND rds.deleted_at IS NULL AND rds.scope_id IN (:...scopeIds))'
154	        );
155	        qb.setParameter('scopeIds', scopeIds);
156	      }
157	    }
158	
159	    if (conditions.length === 0) {
160	      qb.andWhere('1 = 0');
161	      return;
162	    }
163	
164	    qb.andWhere(`(${conditions.join(' OR ')})`, { scopeUserId: userId });
165	  }
166	
167	  private async hasScopedClinicAccess(userId: string, reservationId: string): Promise<boolean> {
168	    const scopeIds = await this.getUserScopeIds(userId);
169	    if (scopeIds.length === 0) {
170	      return false;
171	    }
172	
173	    const count = await this.reservationDataScopeRepository
174	      .createQueryBuilder('rds')
175	      .where('rds.reservation_id = :reservationId', { reservationId })
176	      .andWhere('rds.deleted_at IS NULL')
177	      .andWhere('rds.scope_id IN (:...scopeIds)', { scopeIds })
178	      .getCount();
179	
180	    return count > 0;
181	  }
182	}
