158	  async provisionUser(actorId: string, payload: ProvisionUserDto): Promise<{ user_id: string; username: string; role: string }> {
159	    const actorRoles = await this.getUserRoleNames(actorId);
160	    if (!actorRoles.includes('ops_admin')) {
161	      throw new AppException('FORBIDDEN', 'Only ops_admin can provision users', {}, 403);
162	    }
163	
164	    const existing = await this.userRepository.findOne({ where: { username: payload.username } });
165	    if (existing) {
166	      throw new AppException('AUTH_USERNAME_TAKEN', 'Username is already registered', {}, 409);
167	    }
168	
169	    const question = await this.securityQuestionRepository.findOne({
170	      where: { id: payload.security_question_id, active: true, deletedAt: IsNull() }
171	    });
172	    if (!question) {
173	      throw new AppException('AUTH_SECURITY_QUESTION_NOT_FOUND', 'Security question not found', {}, 404);
174	    }
175	
176	    const allowedRoles = ['staff', 'provider', 'merchant', 'ops_admin', 'analytics_viewer'];
177	    if (!allowedRoles.includes(payload.role)) {
178	      throw new AppException('ACCESS_PROVISION_ROLE_NOT_ALLOWED', 'Requested role cannot be provisioned via this endpoint', {}, 422);
179	    }
180	
181	    const role = await this.roleRepository.findOne({ where: { name: payload.role, deletedAt: IsNull() } });
182	    if (!role) {
183	      throw new AppException('AUTH_ROLE_NOT_FOUND', 'Requested role is not available', {}, 422);
184	    }
185	
186	    const passwordHash = await bcrypt.hash(payload.password, 10);
187	    const answerHash = await bcrypt.hash(payload.security_answer.toLowerCase().trim(), 10);
188	
189	    const queryRunner = this.dataSource.createQueryRunner();
190	    await queryRunner.connect();
191	    await queryRunner.startTransaction();
192	
193	    try {
194	      const user = await queryRunner.manager.save(
195	        UserEntity,
196	        this.userRepository.create({
197	          username: payload.username,
198	          passwordHash,
199	          status: 'ACTIVE'
200	        })
201	      );
202	
203	      await queryRunner.manager.save(
204	        SecurityAnswerEntity,
205	        this.securityAnswerRepository.create({
206	          userId: user.id,
207	          questionId: payload.security_question_id,
208	          answerHash
209	        })
210	      );
211	
212	      await this.assignRoleIdsToUser(user.id, [role.id], queryRunner.manager);
213	
214	      if (['staff', 'provider', 'merchant'].includes(role.name)) {
215	        const actorScopeRows = await this.userDataScopeRepository.find({
216	          where: { userId: actorId, deletedAt: IsNull() },
217	          select: { scopeId: true }
218	        });
219	        const scopeIds = [...new Set(actorScopeRows.map((row) => row.scopeId))];
220	
221	        if (scopeIds.length === 0) {
222	          throw new AppException('ACCESS_PROVISION_SCOPE_REQUIRED', 'Provisioner must have at least one data scope', {}, 422);
223	        }
224	
225	        await queryRunner.manager.save(
226	          UserDataScopeEntity,
227	          scopeIds.map((scopeId) =>
228	            this.userDataScopeRepository.create({
229	              userId: user.id,
230	              scopeId
231	            })
232	          )
233	        );
234	      }
235	
236	      await queryRunner.commitTransaction();
237	
238	      await this.auditService.appendLog({
239	        actorId,
240	        action: 'access.user.provision',
241	        entityType: 'user',
242	        entityId: user.id,
243	        payload: {
244	          username: user.username,
245	          role: role.name
246	        }
247	      });
248	
249	      return {
250	        user_id: user.id,
251	        username: user.username,
252	        role: role.name
253	      };
254	    } catch (error) {
255	      await queryRunner.rollbackTransaction();
256	      throw error;
257	    } finally {
258	      await queryRunner.release();
259	    }
260	  }
