22	    credentials: true,
23	  });
24	
25	  app.use(json({ limit: '25mb' }));
26	  app.use(urlencoded({ limit: '25mb', extended: true }));
27	
28	  app.use((req: { requestId?: string }, res: { setHeader: (name: string, value: string) => void }, next: () => void) => {
29	    const requestId = randomUUID();
30	    req.requestId = requestId;
31	    res.setHeader('x-request-id', requestId);
32	    next();
33	  });
34	
35	  const apiPrefix = process.env.API_PREFIX ?? 'api/v1';
36	  const normalizedPrefix = apiPrefix.startsWith('/') ? apiPrefix : `/${apiPrefix}`;
37	  app.setGlobalPrefix(apiPrefix);
38	
39	  app.useGlobalPipes(
40	    new ValidationPipe({
41	      transform: true,
42	      whitelist: true,
43	      forbidNonWhitelisted: true,
44	      transformOptions: { enableImplicitConversion: true }
45	    })
46	  );
47	
48	  const swaggerConfig = new DocumentBuilder()
49	    .setTitle('CareReserve API')
50	    .setDescription(
51	      'CareReserve modular monolith API. Complements docs/api-spec.md. Try it out uses this host; route paths already include the configured API prefix.'
52	    )
53	    .setVersion('1.0.0')
54	    // Server is "/" only: Nest embeds globalPrefix in each path (e.g. /api/v1/auth/register). addServer("/api/v1") would produce /api/v1/api/v1/... in Swagger UI.
55	    .addServer('/', 'This host (paths include API prefix)')
56	    .addBearerAuth(
57	      {
58	        type: 'http',
59	        scheme: 'bearer',
60	        bearerFormat: 'JWT',
61	        name: 'Authorization',
62	        in: 'header',
63	        description: 'Authorization: Bearer <token>'
64	      },
65	      'bearer'
66	    )
67	    .build();
68	
69	  const swaggerDocument = SwaggerModule.createDocument(app, swaggerConfig, {
70	    deepScanRoutes: true
71	  });
72	  // Mount under the same global prefix as controllers (e.g. /api/v1/docs), not /api/docs —
73	  // otherwise Swagger path and static assets do not match what people expect when API_PREFIX=api/v1.
74	  SwaggerModule.setup('docs', app, swaggerDocument, {
