76	    swaggerOptions: {
77	      persistAuthorization: true
78	    }
79	  });
80	
81	  const swaggerPath = `${normalizedPrefix}/docs`.replace(/\/{2,}/g, '/');
82	  // Common mistake: /api/docs — Swagger actually lives under the same prefix as the API (e.g. /api/v1/docs).
83	  const httpServer = app.getHttpAdapter().getInstance();
84	  httpServer.get('/api/docs', (_req: Request, res: Response) => {
85	    res.redirect(302, swaggerPath);
86	  });
