107	export function validateEnv(config: Record<string, unknown>): EnvironmentVariables {
108	  const validated = plainToInstance(EnvironmentVariables, config, {
109	    enableImplicitConversion: true
110	  });
111	
112	  const errors = validateSync(validated, { skipMissingProperties: false });
113	
114	  if (errors.length > 0) {
115	    throw new Error(errors.toString());
116	  }
117	
118	  assertStrongSecret('JWT_SECRET', validated.JWT_SECRET);
119	  assertStrongSecret('IDENTITY_DOC_ENCRYPTION_KEY', validated.IDENTITY_DOC_ENCRYPTION_KEY);
120	
121	  return validated;
122	}
123	
124	function assertStrongSecret(name: string, value: string): void {
125	  const trimmed = value.trim();
126	  const normalized = trimmed.toLowerCase();
127	
128	  const weakDefaults = new Set([
129	    'change-me',
130	    'change_me',
131	    'changeme',
132	    'change-me-identity-doc-key',
133	    'secret',
134	    'default',
135	    'password',
136	    'test',
137	    'dev'
138	  ]);
139	
140	  if (weakDefaults.has(normalized) || normalized.includes('change-me')) {
141	    throw new Error(`${name} is insecure. Use a strong, non-default secret.`);
142	  }
143	
144	  if (trimmed.length < 32) {
145	    throw new Error(`${name} is too short. Minimum length is 32 characters.`);
146	  }
147	
148	  const hasUpper = /[A-Z]/.test(trimmed);
149	  const hasLower = /[a-z]/.test(trimmed);
150	  const hasDigit = /\d/.test(trimmed);
151	  const hasSymbol = /[^A-Za-z0-9]/.test(trimmed);
152	  const complexityScore = [hasUpper, hasLower, hasDigit, hasSymbol].filter(Boolean).length;
153	  const uniqueChars = new Set(trimmed).size;
154	
155	  if (complexityScore < 3 || uniqueChars < 10) {
156	    throw new Error(`${name} must be high-entropy (mixed character classes and low repetition).`);
157	  }
158	}
