51	  async createReview(userId: string, reservationId: string, payload: CreateReviewDto): Promise<Record<string, unknown>> {
52	    const reservation = await this.reservationRepository.findOne({ where: { id: reservationId, deletedAt: IsNull() } });
53	    if (!reservation) {
54	      throw new AppException('NOT_FOUND', 'Reservation not found', { reservation_id: reservationId }, 404);
55	    }
56	
57	    const isParticipant = reservation.patientId === userId || reservation.providerId === userId;
58	    if (!isParticipant) {
59	      throw new AppException('FORBIDDEN', 'Reservation is out of scope', { reservation_id: reservationId }, 403);
60	    }
61	
62	    await this.scopePolicyService.assertReservationInScope(userId, reservation);
63	
64	    if (reservation.status !== ReservationStatus.COMPLETED) {
65	      throw new AppException('REVIEW_RESERVATION_NOT_COMPLETED', 'Reviews are allowed only after completion', {}, 422);
66	    }
67	
68	    const completionTransition = await this.transitionRepository.findOne({
69	      where: { reservationId, action: 'COMPLETE' },
70	      order: { createdAt: 'DESC' }
71	    });
72	    const completionTime = completionTransition?.createdAt ?? reservation.updatedAt;
73	    if (isReviewWindowExpired(completionTime)) {
74	      throw new AppException('REVIEW_WINDOW_EXPIRED', 'Review window has expired', {}, 422);
75	    }
76	
77	    if (payload.target_user_id === userId) {
78	      throw new AppException('REVIEW_SELF_NOT_ALLOWED', 'Self-review is not allowed', {}, 422);
79	    }
80	
81	    const counterpartyIds = [reservation.patientId, reservation.providerId].filter((id): id is string => Boolean(id && id !== userId));
82	    if (!counterpartyIds.includes(payload.target_user_id)) {
83	      throw new AppException(
84	        'REVIEW_TARGET_USER_INVALID',
85	        'target_user_id must be the reservation counterparty',
86	        { reservation_id: reservationId },
87	        422
88	      );
89	    }
90	
91	    const duplicateDirectional = await this.reviewRepository.findOne({
92	      where: {
93	        reservationId,
94	        reviewerUserId: userId,
95	        targetUserId: payload.target_user_id,
96	        deletedAt: IsNull()
97	      }
98	    });
99	    if (duplicateDirectional) {
100	      throw new AppException('REVIEW_ALREADY_EXISTS', 'Review already exists for this reservation and direction', {}, 409);
101	    }
102	
103	    const review = await this.reviewRepository.save(
104	      this.reviewRepository.create({
105	        reservationId,
106	        reviewerUserId: userId,
107	        targetUserId: payload.target_user_id,
108	        dimensions: payload.dimensions,
109	        comment: payload.comment ?? null
110	      })
111	    );
112	
113	    await this.auditService.appendLog({
114	      entityType: 'review',
115	      entityId: review.id,
116	      action: 'trust.review.create',
117	      actorId: userId,
118	      payload: {
119	        reservation_id: reservationId,
120	        target_user_id: payload.target_user_id
121	      }
122	    });
123	
124	    return this.mapReview(review);
125	  }
