1	import {
2	  CallHandler,
3	  ExecutionContext,
4	  Injectable,
5	  NestInterceptor
6	} from '@nestjs/common';
7	import { Reflector } from '@nestjs/core';
8	import { createHash } from 'node:crypto';
9	import { Observable, from, of, switchMap } from 'rxjs';
10	import { IDEMPOTENT_KEY } from '../../common/decorators/idempotent.decorator';
11	import { AppException } from '../../common/exceptions/app.exception';
12	import { RequestWithContext } from '../../common/types/request-with-context';
13	import { AuthService } from '../auth/auth.service';
14	import { IdempotencyService } from './idempotency.service';
15	
16	@Injectable()
17	export class IdempotencyInterceptor implements NestInterceptor {
18	  constructor(
19	    private readonly reflector: Reflector,
20	    private readonly idempotencyService: IdempotencyService,
21	    private readonly authService: AuthService
22	  ) {}
23	
24	  intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
25	    const idempotent = this.reflector.getAllAndOverride<boolean>(IDEMPOTENT_KEY, [
26	      context.getHandler(),
27	      context.getClass()
28	    ]);
29	
30	    if (!idempotent) {
31	      return next.handle();
32	    }
33	
34	    const httpContext = context.switchToHttp();
35	    const request = httpContext.getRequest<RequestWithContext>();
36	    const response = httpContext.getResponse<{ status: (statusCode: number) => void; statusCode: number }>();
37	    const keyHeader = request.headers['idempotency-key'];
38	    const idempotencyKey = Array.isArray(keyHeader) ? keyHeader[0] : keyHeader;
39	
40	    if (!idempotencyKey) {
41	      throw new AppException('IDEMPOTENCY_KEY_REQUIRED', 'Idempotency-Key header is required', {}, 400);
42	    }
43	
44	    const endpoint = `${request.method}:${request.originalUrl.split('?')[0]}`;
45	    const requestHash = createHash('sha256').update(JSON.stringify(request.body ?? {})).digest('hex');
46	
47	    return from(this.idempotencyService.findByKeyAndEndpoint(idempotencyKey, endpoint)).pipe(
48	      switchMap((existing) => {
49	        if (existing) {
50	          if (existing.requestHash && existing.requestHash !== requestHash) {
51	            throw new AppException(
52	              'IDEMPOTENCY_KEY_CONFLICT',
53	              'Idempotency-Key has already been used with a different payload',
54	              {},
55	              409
56	            );
57	          }
58	
59	          return from(this.hydrateIdempotentRegisterBody(endpoint, existing.responseBody)).pipe(
60	            switchMap((body) => {
61	              response.status(existing.responseStatus ?? 200);
62	              return of(body);
63	            })
64	          );
65	        }
66	
67	        return next.handle().pipe(
68	          switchMap((handlerResponse) =>
69	            from(
70	              this.idempotencyService.saveResult({
71	                key: idempotencyKey,
72	                endpoint,
73	                requestHash,
74	                responseStatus: response.statusCode,
75	                responseBody: handlerResponse
76	              })
77	            ).pipe(switchMap(() => of(handlerResponse)))
78	          )
79	        );
80	      })
81	    );
82	  }
83	
84	  /**
85	   * Older idempotency rows for POST /auth/register may omit access_token; replay must still return a session.
86	   */
87	  private async hydrateIdempotentRegisterBody(endpoint: string, responseBody: unknown): Promise<unknown> {
88	    const body: unknown = responseBody ?? null;
89	    if (
90	      !body ||
91	      typeof body !== 'object' ||
92	      Array.isArray(body) ||
93	      !endpoint.endsWith('/auth/register')
94	    ) {
95	      return body;
96	    }
97	
98	    const rec = body as Record<string, unknown>;
99	    const userId = rec.user_id;
100	    const token = rec.access_token;
101	    if (typeof userId !== 'string' || (typeof token === 'string' && token.length > 0)) {
102	      return body;
103	    }
104	
105	    const auth = await this.authService.issueAuthenticatedSession(userId);
106	    return { ...rec, ...auth };
107	  }
108	}
