1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository } from 'typeorm';
4	import { AppException } from '../../common/exceptions/app.exception';
5	import { ScopePolicyService } from '../access-control/scope-policy.service';
6	import { NotificationEntity } from '../communication/entities/notification.entity';
7	import { ReservationEntity, ReservationStatus } from '../reservation/entities/reservation.entity';
8	import { SyncPullQueryDto } from './dto/sync-pull-query.dto';
9	import { SyncEntityType, SyncOperation, SyncPushDto } from './dto/sync-push.dto';
10	
11	type SyncConflict = {
12	  entity_id: string;
13	  server_version: number | null;
14	  reason: string;
15	};
16	
17	type SyncAccepted = {
18	  entity_type: SyncEntityType;
19	  entity_id: string;
20	  version: number;
21	  updated_at: string;
22	};
23	
24	@Injectable()
25	export class SyncService {
26	  constructor(
27	    private readonly scopePolicyService: ScopePolicyService,
28	    @InjectRepository(ReservationEntity)
29	    private readonly reservationRepository: Repository<ReservationEntity>,
30	    @InjectRepository(NotificationEntity)
31	    private readonly notificationRepository: Repository<NotificationEntity>
32	  ) {}
33	
34	  async pushChanges(userId: string, payload: SyncPushDto): Promise<Record<string, unknown>> {
35	    const accepted: SyncAccepted[] = [];
36	    const conflicts: SyncConflict[] = [];
37	
38	    for (const change of payload.changes) {
39	      const entityType = this.parseEntityType(change.entity_type);
40	      const operation = this.parseOperation(change.operation);
41	
42	      if (entityType !== SyncEntityType.RESERVATION) {
43	        throw new AppException('SYNC_ENTITY_PUSH_NOT_SUPPORTED', 'Push currently supports reservation entities only', {}, 422);
44	      }
45	
46	      const result = await this.applyReservationChange(userId, {
47	        entity_id: change.entity_id,
48	        operation,
49	        payload: change.payload,
50	        base_version: change.base_version,
51	        updated_at: change.updated_at
52	      });
53	
54	      if ('reason' in result) {
55	        conflicts.push(result);
56	      } else {
57	        accepted.push(result);
58	      }
59	    }
60	
61	    return {
62	      accepted,
63	      conflicts
64	    };
65	  }
66	
67	  async pullChanges(userId: string, query: SyncPullQueryDto): Promise<Record<string, unknown>> {
68	    this.assertCursor(query);
69	
70	    const requestedTypes = query.entity_types?.length ? query.entity_types : [SyncEntityType.RESERVATION];
71	    const entityTypes = Array.from(new Set(requestedTypes.map((item) => this.parseEntityType(item))));
72	
73	    const changes: Array<Record<string, unknown>> = [];
74	    const sinceUpdatedAt = query.since_updated_at ? new Date(query.since_updated_at) : null;
75	    const sinceVersion = typeof query.since_version === 'number' ? query.since_version : null;
76	    const perEntityFetchLimit = query.page * query.page_size;
77	
78	    if (entityTypes.includes(SyncEntityType.RESERVATION)) {
79	      const reservations = await this.getScopedReservations(userId, sinceUpdatedAt, sinceVersion, perEntityFetchLimit);
80	      changes.push(
81	        ...reservations.map((item) => ({
82	          entity_type: SyncEntityType.RESERVATION,
83	          entity_id: item.id,
84	          version: item.version,
85	          updated_at: item.updatedAt.toISOString(),
86	          tombstone: Boolean(item.deletedAt),
87	          payload: {
88	            status: item.status,
89	            start_time: item.startTime?.toISOString() ?? null,
90	            end_time: item.endTime?.toISOString() ?? null
91	          }
92	        }))
93	      );
94	    }
95	
96	    if (entityTypes.includes(SyncEntityType.NOTIFICATION)) {
97	      const notifications = await this.getScopedNotifications(userId, sinceUpdatedAt, sinceVersion, perEntityFetchLimit);
98	      changes.push(
99	        ...notifications.map((item) => ({
100	          entity_type: SyncEntityType.NOTIFICATION,
101	          entity_id: item.id,
102	          version: item.version,
103	          updated_at: item.updatedAt.toISOString(),
104	          tombstone: Boolean(item.deletedAt),
105	            payload: {
106	              type: item.type,
107	              title: item.title,
108	              body: item.body,
109	              payload: item.payload,
110	              read_at: item.readAt?.toISOString() ?? null
111	            }
112	          }))
113	        );
114	    }
115	
116	    const sorted = changes.sort((a, b) => {
117	      const updatedAtDiff = String(a.updated_at).localeCompare(String(b.updated_at));
118	      if (updatedAtDiff !== 0) {
119	        return updatedAtDiff;
120	      }
121	      return String(a.entity_id).localeCompare(String(b.entity_id));
122	    });
123	    const paged = sorted.slice((query.page - 1) * query.page_size, query.page * query.page_size);
124	
125	    return {
126	      changes: paged,
127	      page: query.page,
128	      page_size: query.page_size,
129	      total: sorted.length
130	    };
131	  }
132	
133	  private async applyReservationChange(
134	    userId: string,
135	    change: {
136	      entity_id: string;
137	      operation: SyncOperation;
138	      payload: Record<string, unknown>;
139	      base_version: number;
140	      updated_at: string;
141	    }
142	  ): Promise<SyncAccepted | SyncConflict> {
143	    const reservation = await this.reservationRepository.findOne({ where: { id: change.entity_id } });
144	    if (!reservation) {
145	      return this.toConflict(change.entity_id, null, 'SYNC_ENTITY_NOT_FOUND');
146	    }
147	
148	    if (reservation.deletedAt) {
149	      return this.toConflict(change.entity_id, reservation.version, 'SYNC_ENTITY_DELETED');
150	    }
151	
152	    if (reservation.version !== change.base_version) {
153	      return this.toConflict(change.entity_id, reservation.version, 'SYNC_VERSION_CONFLICT');
154	    }
155	
156	    if (change.operation !== SyncOperation.UPSERT) {
157	      throw new AppException('SYNC_OPERATION_NOT_ALLOWED', 'Unsupported sync operation for reservation', {}, 422);
158	    }
159	
160	    const roles = await this.scopePolicyService.getRoles(userId);
161	    const canUpdate =
162	      roles.includes('ops_admin') ||
163	      roles.includes('staff') ||
164	      (roles.includes('provider') && reservation.providerId === userId) ||
165	      reservation.patientId === userId;
166	    if (!canUpdate) {
167	      throw new AppException('FORBIDDEN', 'Insufficient permissions', {}, 403);
168	    }
169	
170	    await this.scopePolicyService.assertReservationInScope(userId, reservation, roles);
171	
172	    if (reservation.status !== ReservationStatus.CONFIRMED) {
173	      throw new AppException('RESERVATION_INVALID_TRANSITION', 'Only CONFIRMED reservations can be updated via sync', {}, 422);
174	    }
175	
176	    const startTime = typeof change.payload.start_time === 'string' ? new Date(change.payload.start_time) : null;
177	    const endTime = typeof change.payload.end_time === 'string' ? new Date(change.payload.end_time) : null;
178	
179	    if (!startTime || !endTime || Number.isNaN(startTime.getTime()) || Number.isNaN(endTime.getTime())) {
180	      throw new AppException('SYNC_INVALID_PAYLOAD', 'start_time and end_time must be valid ISO timestamps', {}, 422);
181	    }
182	
183	    if (endTime.getTime() <= startTime.getTime()) {
184	      throw new AppException('RESERVATION_INVALID_TIME_RANGE', 'end_time must be greater than start_time', {}, 422);
185	    }
186	
187	    if (typeof change.payload.status === 'string' && change.payload.status !== reservation.status) {
188	      throw new AppException('SYNC_FIELD_NOT_ALLOWED', 'status cannot be changed through sync push', {}, 422);
189	    }
190	
191	    const updatedAt = new Date(change.updated_at);
192	    if (Number.isNaN(updatedAt.getTime())) {
193	      throw new AppException('SYNC_INVALID_PAYLOAD', 'updated_at must be a valid ISO timestamp', {}, 422);
194	    }
195	
196	    reservation.startTime = startTime;
197	    reservation.endTime = endTime;
198	    reservation.version += 1;
199	    reservation.updatedAt = updatedAt;
200	    await this.reservationRepository.save(reservation);
201	
202	    return {
203	      entity_type: SyncEntityType.RESERVATION,
204	      entity_id: reservation.id,
205	      version: reservation.version,
206	      updated_at: reservation.updatedAt.toISOString()
207	    };
208	  }
209	
210	  private async getScopedReservations(
211	    userId: string,
212	    sinceUpdatedAt: Date | null,
213	    sinceVersion: number | null,
214	    limit: number
215	  ): Promise<ReservationEntity[]> {
216	    const roles = await this.scopePolicyService.getRoles(userId);
217	    const qb = this.reservationRepository.createQueryBuilder('r');
218	
219	    await this.scopePolicyService.applyReservationScopeQuery(qb, userId, roles);
220	
221	    if (sinceUpdatedAt) {
222	      qb.andWhere('r.updated_at > :sinceUpdatedAt', { sinceUpdatedAt: sinceUpdatedAt.toISOString() });
223	    }
224	    if (sinceVersion !== null) {
225	      qb.andWhere('r.version > :sinceVersion', { sinceVersion });
226	    }
227	
228	    qb.orderBy('r.updated_at', 'ASC').addOrderBy('r.id', 'ASC').take(limit);
229	    return qb.getMany();
230	  }
231	
232	  private getScopedNotifications(
233	    userId: string,
234	    sinceUpdatedAt: Date | null,
235	    sinceVersion: number | null,
236	    limit: number
237	  ): Promise<NotificationEntity[]> {
238	    const qb = this.notificationRepository.createQueryBuilder('n').where('n.user_id = :userId', { userId });
239	
240	    if (sinceUpdatedAt) {
241	      qb.andWhere('n.updated_at > :sinceUpdatedAt', { sinceUpdatedAt: sinceUpdatedAt.toISOString() });
242	    }
243	    if (sinceVersion !== null) {
244	      qb.andWhere('n.version > :sinceVersion', { sinceVersion });
245	    }
246	
247	    qb.orderBy('n.updated_at', 'ASC').addOrderBy('n.id', 'ASC').take(limit);
248	    return qb.getMany();
249	  }
250	
251	  private parseEntityType(entityType: string): SyncEntityType {
252	    if (entityType === SyncEntityType.RESERVATION || entityType === SyncEntityType.NOTIFICATION) {
253	      return entityType;
254	    }
255	
256	    throw new AppException('SYNC_ENTITY_NOT_SUPPORTED', 'Unknown sync entity_type', { entity_type: entityType }, 422);
257	  }
258	
259	  private parseOperation(operation: string): SyncOperation {
260	    if (operation === SyncOperation.UPSERT || operation === SyncOperation.DELETE) {
261	      return operation;
262	    }
263	
264	    throw new AppException('SYNC_OPERATION_NOT_SUPPORTED', 'Unknown sync operation', { operation }, 422);
265	  }
266	
267	  private assertCursor(query: SyncPullQueryDto): void {
268	    if (!query.since_updated_at && !query.since_version) {
269	      throw new AppException('SYNC_CURSOR_REQUIRED', 'Either since_updated_at or since_version is required', {}, 422);
270	    }
271	  }
272	
273	  private toConflict(entityId: string, serverVersion: number | null, reason: string): SyncConflict {
274	    return {
275	      entity_id: entityId,
276	      server_version: serverVersion,
277	      reason
278	    };
279	  }
280	}
