10	@Injectable()
11	export class SensitiveWordService {
12	  private cachedWords: Set<string> | null = null;
13	  private cacheExpiry: number = 0;
14	
15	  constructor(
16	    private readonly configService: ConfigService,
17	    private readonly accessControlService: AccessControlService,
