22	
23	  async createSensitiveWord(userId: string, payload: { word: string }): Promise<Record<string, unknown>> {
24	    await this.requireOpsAdmin(userId);
25	    const normalized = payload.word.trim().toLowerCase();
26	    if (!normalized) {
27	      throw new AppException('VALIDATION_ERROR', 'word must not be empty', {}, 422);
28	    }
29	
30	    const existing = await this.sensitiveWordRepository.findOne({ where: { word: normalized } });
31	    if (existing) {
32	      throw new AppException('SENSITIVE_WORD_EXISTS', 'Sensitive word already exists', {}, 409);
33	    }
34	
35	    const entity = this.sensitiveWordRepository.create({ word: normalized, active: true });
36	    const saved = await this.sensitiveWordRepository.save(entity);
37	
38	    await this.auditService.appendLog({
39	      entityType: 'sensitive_word',
40	      entityId: saved.id,
41	      action: 'sensitive_word.create',
42	      actorId: userId,
43	      payload: {
44	        word: saved.word,
45	        active: saved.active
46	      }
47	    });
48	
49	    return this.mapSensitiveWord(saved);
50	  }
51	
52	  async listSensitiveWords(userId: string, query: { active?: string }): Promise<Record<string, unknown>> {
53	    await this.requireOpsAdmin(userId);
54	
55	    const qb = this.sensitiveWordRepository.createQueryBuilder('sw');
56	    if (query.active === 'true') {
57	      qb.andWhere('sw.active = true');
58	    }
59	    if (query.active === 'false') {
60	      qb.andWhere('sw.active = false');
61	    }
62	
63	    qb.orderBy('sw.word', 'ASC').addOrderBy('sw.id', 'ASC');
64	    const items = await qb.getMany();
