71	
72	  async updateSensitiveWord(userId: string, wordId: string, payload: { word: string }): Promise<Record<string, unknown>> {
73	    await this.requireOpsAdmin(userId);
74	
75	    const word = await this.sensitiveWordRepository.findOne({ where: { id: wordId } });
76	    if (!word) {
77	      throw new AppException('NOT_FOUND', 'Sensitive word not found', { word_id: wordId }, 404);
78	    }
79	
80	    const normalized = payload.word.trim().toLowerCase();
81	    if (!normalized) {
82	      throw new AppException('VALIDATION_ERROR', 'word must not be empty', {}, 422);
83	    }
84	
85	    const duplicate = await this.sensitiveWordRepository.findOne({ where: { word: normalized } });
86	    if (duplicate && duplicate.id !== wordId) {
87	      throw new AppException('SENSITIVE_WORD_EXISTS', 'Sensitive word already exists', {}, 409);
88	    }
89	
90	    const before = word.word;
91	    word.word = normalized;
92	    const saved = await this.sensitiveWordRepository.save(word);
93	
94	    await this.auditService.appendLog({
95	      entityType: 'sensitive_word',
96	      entityId: saved.id,
97	      action: 'sensitive_word.update',
98	      actorId: userId,
99	      payload: {
100	        before,
101	        after: saved.word,
102	        active: saved.active
103	      }
104	    });
105	
106	    return this.mapSensitiveWord(saved);
107	  }
108	
109	  async toggleSensitiveWord(userId: string, wordId: string, payload: { active: string }): Promise<Record<string, unknown>> {
110	    await this.requireOpsAdmin(userId);
111	
112	    const word = await this.sensitiveWordRepository.findOne({ where: { id: wordId } });
113	    if (!word) {
114	      throw new AppException('NOT_FOUND', 'Sensitive word not found', { word_id: wordId }, 404);
115	    }
116	
117	    const active = payload.active === 'true';
118	    const before = word.active;
119	    word.active = active;
120	    const saved = await this.sensitiveWordRepository.save(word);
121	
122	    await this.auditService.appendLog({
123	      entityType: 'sensitive_word',
124	      entityId: saved.id,
125	      action: 'sensitive_word.toggle',
126	      actorId: userId,
127	      payload: {
128	        before_active: before,
129	        after_active: saved.active,
130	        word: saved.word
131	      }
132	    });
133	
134	    return this.mapSensitiveWord(saved);
135	  }
136	
137	  async enforceSensitiveWords(content: string): Promise<void> {
138	    let allWords: Set<string>;
139	    if (this.cachedWords !== null && Date.now() < this.cacheExpiry) {
140	      allWords = this.cachedWords;
141	    } else {
142	      const wordsFromDb = await this.sensitiveWordRepository.find({ where: { active: true } });
143	      const wordsFromEnv = (this.configService.get<string>('SENSITIVE_WORDS') ?? '')
144	        .split(',')
145	        .map((word) => word.trim().toLowerCase())
146	        .filter(Boolean);
147	
148	      allWords = new Set<string>([
149	        ...wordsFromDb.map((row) => row.word.toLowerCase()),
150	        ...wordsFromEnv
151	      ]);
