8	@Injectable()
9	export class AuditService {
10	  constructor(
11	    @InjectRepository(AuditLogEntity)
12	    private readonly auditRepository: Repository<AuditLogEntity>,
13	    private readonly dataSource: DataSource
14	  ) {}
