16	  async appendLog(input: {
17	    entityType: string;
18	    entityId?: string | null;
19	    action: string;
20	    actorId?: string | null;
21	    payload?: Record<string, unknown>;
22	  }): Promise<AuditLogEntity> {
23	    const queryRunner = this.dataSource.createQueryRunner();
24	    await queryRunner.connect();
25	    await queryRunner.startTransaction();
26	
27	    try {
28	      // Serialize chain-head updates across concurrent writers in the same DB.
29	      await queryRunner.query(`SELECT pg_advisory_xact_lock(hashtext('audit_log_chain'))`);
30	
31	      const previous = await queryRunner.manager
32	        .createQueryBuilder(AuditLogEntity, 'audit')
33	        .orderBy('audit.created_at', 'DESC')
34	        .addOrderBy('audit.id', 'DESC')
35	        .limit(1)
36	        .useTransaction(true)
37	        .getOne();
38	
39	      const payload = input.payload ?? {};
40	      const createdAt = new Date().toISOString();
41	      const hashInput = this.buildHashInput({
42	        previous_hash: previous?.entryHash ?? null,
43	        entity_type: input.entityType,
44	        entity_id: input.entityId ?? null,
45	        action: input.action,
46	        actor_id: input.actorId ?? null,
47	        payload,
48	        created_at: createdAt
49	      });
50	
51	      const entryHash = createHash('sha256').update(hashInput).digest('hex');
52	
53	      const entity = this.auditRepository.create({
54	        entityType: input.entityType,
55	        entityId: input.entityId ?? null,
56	        action: input.action,
57	        actorId: input.actorId ?? null,
58	        previousHash: previous?.entryHash ?? null,
59	        entryHash,
60	        hashInput,
61	        payload
62	      });
63	
64	      const saved = await queryRunner.manager.save(entity);
65	      await queryRunner.commitTransaction();
66	      return saved;
67	    } catch (error) {
68	      await queryRunner.rollbackTransaction();
69	      throw error;
70	    } finally {
71	      await queryRunner.release();
72	    }
73	  }
74	
75	  async verifyIntegrity(input?: {
76	    from?: string;
77	    to?: string;
78	    limit?: number;
79	  }): Promise<{
80	    valid: boolean;
81	    first_invalid_record_id: string | null;
82	    checked_count: number;
83	    from: string | null;
84	    to: string | null;
85	  }> {
86	    const qb = this.auditRepository.createQueryBuilder('audit').where('audit.deleted_at IS NULL');
87	    if (input?.from) {
88	      qb.andWhere('audit.created_at >= :from', { from: input.from });
89	    }
90	    if (input?.to) {
91	      qb.andWhere('audit.created_at <= :to', { to: input.to });
92	    }
93	
94	    qb.orderBy('audit.created_at', 'ASC').addOrderBy('audit.id', 'ASC');
95	    qb.take(input?.limit && input.limit > 0 ? input.limit : 5000);
96	    const rows = await qb.getMany();
97	
98	    let checkedCount = 0;
99	    let previousEntryHash: string | null = null;
100	
101	    for (let i = 0; i < rows.length; i += 1) {
102	      const row = rows[i]!;
103	      checkedCount += 1;
104	
105	      if ((row.previousHash ?? null) !== previousEntryHash) {
106	        return {
107	          valid: false,
108	          first_invalid_record_id: row.id,
109	          checked_count: checkedCount,
110	          from: rows[0]?.createdAt.toISOString() ?? null,
111	          to: rows[rows.length - 1]?.createdAt.toISOString() ?? null
112	        };
113	      }
114	
115	      if (row.hashInput) {
116	        const recomputed = createHash('sha256').update(row.hashInput).digest('hex');
117	        if (recomputed !== row.entryHash) {
118	          return {
119	            valid: false,
120	            first_invalid_record_id: row.id,
121	            checked_count: checkedCount,
122	            from: rows[0]?.createdAt.toISOString() ?? null,
123	            to: rows[rows.length - 1]?.createdAt.toISOString() ?? null
124	          };
125	        }
126	      }
127	
128	      previousEntryHash = row.entryHash;
129	    }
130	
131	    return {
132	      valid: true,
133	      first_invalid_record_id: null,
134	      checked_count: checkedCount,
135	      from: rows[0]?.createdAt.toISOString() ?? input?.from ?? null,
136	      to: rows[rows.length - 1]?.createdAt.toISOString() ?? input?.to ?? null
137	    };
138	  }
