140	  async getLogs(query: AuditLogQueryDto): Promise<{
141	    items: AuditLogEntity[];
142	    page: number;
143	    page_size: number;
144	    total: number;
145	  }> {
146	    const qb = this.auditRepository.createQueryBuilder('audit').where('audit.deleted_at IS NULL');
147	
148	    if (query.actor_id) {
149	      qb.andWhere('audit.actor_id = :actorId', { actorId: query.actor_id });
150	    }
151	
152	    if (query.entity_type) {
153	      qb.andWhere('audit.entity_type = :entityType', { entityType: query.entity_type });
154	    }
155	
156	    if (query.from) {
157	      qb.andWhere('audit.created_at >= :from', { from: query.from });
158	    }
159	
160	    if (query.to) {
161	      qb.andWhere('audit.created_at <= :to', { to: query.to });
162	    }
163	
164	    const page = query.page;
165	    const pageSize = query.page_size;
166	    qb.orderBy('audit.created_at', 'DESC').addOrderBy('audit.id', 'DESC').skip((page - 1) * pageSize).take(pageSize);
167	
168	    const [items, total] = await qb.getManyAndCount();
169	
170	    return {
171	      items,
172	      page,
173	      page_size: pageSize,
174	      total
175	    };
176	  }
177	
178	  private buildHashInput(input: {
179	    previous_hash: string | null;
180	    entity_type: string;
181	    entity_id: string | null;
182	    action: string;
183	    actor_id: string | null;
184	    payload: Record<string, unknown>;
185	    created_at: string;
186	  }): string {
187	    return this.stableStringify(input);
188	  }
189	
190	  private stableStringify(value: unknown): string {
191	    return JSON.stringify(this.sortDeep(value));
192	  }
193	
194	  private sortDeep(value: unknown): unknown {
195	    if (Array.isArray(value)) {
196	      return value.map((item) => this.sortDeep(item));
197	    }
198	
199	    if (value && typeof value === 'object') {
200	      const sorted: Record<string, unknown> = {};
201	      const keys = Object.keys(value as Record<string, unknown>).sort((a, b) => a.localeCompare(b));
202	      for (const key of keys) {
203	        sorted[key] = this.sortDeep((value as Record<string, unknown>)[key]);
204	      }
205	      return sorted;
206	    }
207	
208	    return value;
209	  }
210	}
